238→export const useFollowMutation = (session) =>{
239→    const queryClient = useQueryClient();
240→
241→    return useMutation({
242→        mutationFn: (data) => addFollows(data, session?.access_token),
243→
244→        onMutate: async(data) => {
245→            await queryClient.cancelQueries(['followsData']);
246→            const previousData = queryClient.getQueryData(['followsData']);
247→
248→            queryClient.setQueryData(['followsData'], (old) => {
249→                if(!old) return old;
250→                return{
251→                    ...old,
252→                    followersCount: old.isFollowing ? old.followersCount - 1 : old.followersCount + 1,
253→                    isFollowing: !old.isFollowing
254→                }
255→            })
256→
257→            return {previousData};
258→
259→        },
260→        onError: (err, data, context) => {
261→            queryClient.setQueryData(['followsData'], context.previousData)
262→        },
263→        onSettled: () => {
264→            queryClient.invalidateQueries(['followsData']);
265→        }
266→    })
267→}
