269→export const useReadNotificationMutation = (session) =>{
270→    const queryClient = useQueryClient();
271→    return useMutation({
272→        mutationFn: (data) => readNotification(session?.access_token, data?.notifId, data?.source),
273→        onMutate: async(data) => {
274→            await queryClient.cancelQueries(['notifcounts', session?.user?.id]);
275→            const previousData = queryClient.getQueryData(['notifcount', session?.user?.id])
276→
277→            queryClient.setQueryData(['notifcount', session?.user?.id], (old) => ({count: (old?.count ? old?.count : 0) - 1}));
278→
279→            return{previousData};
280→        },
281→         onError: (err, data, context) => {
282→            queryClient.setQueryData(['notifcount', session?.user?.id], context.previousData)
283→         },
284→         onSettled: () => {
285→            queryClient.invalidateQueries(['notifcount', session?.user?.id]);
286→         }
287→    })
288→}
