383→export const useReactionMutation = (session, userId) => {
384→    const queryClient = useQueryClient();
385→    const inFlightRef = useRef(new Set());
386→
387→    const mutation = useMutation({
388→        mutationFn: (data) => toggleReaction(session?.access_token, data),
389→
390→        onMutate: async (data) => {
391→            queryClient.cancelQueries({ queryKey: ['journals'] });
392→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
393→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
394→
395→            const previousData = [
396→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
397→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
398→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
399→            ];
400→
401→            const updater = (journal) => {
402→                if (journal.id !== data.journalId) return journal;
403→
404→                const currentReaction = journal?.user_reaction;
405→                const currentCount = normalizeCount(journal?.reaction_count?.[0]?.count);
406→
407→                let nextReaction;
408→                let nextCount;
409→
410→                if (currentReaction === data.reactionType) {
411→                    // Toggle off
412→                    nextReaction = null;
413→                    nextCount = Math.max(currentCount - 1, 0);
414→                } else if (currentReaction) {
415→                    // Switch reaction (count stays same)
416→                    nextReaction = data.reactionType;
417→                    nextCount = currentCount;
418→                } else {
419→                    // New reaction
420→                    nextReaction = data.reactionType;
421→                    nextCount = currentCount + 1;
422→                }
423→
424→                return {
425→                    ...journal,
426→                    user_reaction: nextReaction,
427→                    reaction_count: [{ count: nextCount }],
428→                };
429→            };
430→
431→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
432→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
433→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
434→
435→            return { previousData };
436→        },
437→
438→        onError: (err, data, context) => {
439→            context?.previousData?.forEach(([key, value]) => {
440→                queryClient.setQueryData(key, value);
441→            });
442→        },
443→
444→    });
445→
446→    const guardedMutate = (variables, options) => {
447→        const journalKey = toJournalKey(variables?.journalId);
448→        if (journalKey && inFlightRef.current.has(journalKey)) return;
449→
450→        if (journalKey) inFlightRef.current.add(journalKey);
451→
452→        mutation.mutate(variables, {
453→            ...options,
454→            onSettled: (data, error, vars, context) => {
455→                if (journalKey) inFlightRef.current.delete(journalKey);
456→                options?.onSettled?.(data, error, vars, context);
457→            },
458→        });
459→    };
460→
461→    return { ...mutation, mutate: guardedMutate };
462→}
